// Simula cálculo del reporte semanal
// En producción esto vendría de tu base de datos PostgreSQL
const picks = [
  {partido:'Millonarios vs Nacional', prediccion:'LOCAL', resultado:'LOCAL', liga:'Liga BetPlay'},
  {partido:'Liverpool vs Man United', prediccion:'LOCAL', resultado:'LOCAL', liga:'Premier League'},
  {partido:'Real Madrid vs Atletico', prediccion:'LOCAL', resultado:'LOCAL', liga:'LaLiga'},
  {partido:'Bayern vs Dortmund',      prediccion:'LOCAL', resultado:'EMPATE', liga:'Bundesliga'},
  {partido:'PSG vs Arsenal',          prediccion:'VISITANTE', resultado:'VISITANTE', liga:'Champions'},
  {partido:'Junior vs Tolima',        prediccion:'EMPATE', resultado:'LOCAL', liga:'Liga BetPlay'},
  {partido:'Barcelona vs Inter',      prediccion:'LOCAL', resultado:'LOCAL', liga:'Champions'},
];

const total    = picks.length;
const acertados = picks.filter(p => p.prediccion === p.resultado).length;
const fallados  = total - acertados;
const precision = Math.round((acertados / total) * 100);

const listaAciertos = picks
  .filter(p => p.prediccion === p.resultado)
  .slice(0,3)
  .map(p => `✅ ${p.partido} → ${p.prediccion}`)
  .join('\n');

const listaFallos = picks
  .filter(p => p.prediccion !== p.resultado)
  .slice(0,2)
  .map(p => `❌ ${p.partido} → predijimos ${p.prediccion}, fue ${p.resultado}`)
  .join('\n');

const semana = new Date().toLocaleDateString('es-CO', {month:'long', day:'numeric', timeZone:'America/Bogota'});

const msgReporte = `📊 REPORTE SEMANAL — LifeHackIA\n\nSemana del ${semana}\n\nResultados: ${acertados} de ${total} picks correctos (${precision}% precisión)\n\n${listaAciertos}\n${listaFallos}\n\n📈 Precisión acumulada: 68.6%\n🏆 Mejor liga esta semana: Premier League\n\n👉 Únete gratis: @LifeHackIAPronosticos\n👑 Premium $19.900/mes: [LINK_WOMPI]\n\n#LifeHackIA #Fútbol #Transparencia`;

return [{ json: { msgReporte, precision, acertados, total, semana } }];
